+import { z } from "zod";
+import { randomBytes } from "node:crypto";
+import { db } from "../db";
+import type { UserContext } from "../auth";
+
+const PLATFORMS: Record<string, number> = {
+  "Ruby": 0, "Ruby on Rails": 1, "PHP": 2, "Laravel": 3, "JavaScript": 4,
+  "Android": 5, "Apple": 6, "Dart": 7, "Flutter": 8, "Elixir": 9,
