export const PLATFORM_NAMES = Object.keys(PLATFORMS);

export const createProjectSchema = z.object({
  name: z.string().min(1).max(255).describe("Project name"),
  platform: z.string().describe("Platform name (e.g. 'Ruby on Rails', 'Node.js', 'Python')"),
  timezone: z.string().default("UTC").describe("Project timezone (e.g. 'UTC', 'America/New_York')"),
});

export function createProject(
  ctx: UserContext,
  params: z.infer<typeof createProjectSchema>
): object {
  if (ctx.user.role !== 0) {
    return { error: "Admin access required to create projects" };
  }

  const platformId = PLATFORMS[params.platform];
  if (platformId === undefined) {
    return {
      error: `Unknown platform '${params.platform}'. Use list_platforms to see available options.`,
    };
  }

  const now = new Date().toISOString();
  const token = randomBytes(32).toString("hex");

  const insertProject = db.prepare(
    `INSERT INTO projects (name, platform, timezone, token, groups_count, reports_count, created_at, updated_at)
     VALUES (?, ?, ?, ?, 0, 0, ?, ?)`
  );
  const insertMembership = db.prepare(
    `INSERT INTO project_memberships (project_id, user_id, created_at, updated_at)
     VALUES (?, ?, ?, ?)`
  );

  const transaction = db.transaction(() => {
    const result = insertProject.run(params.name, platformId, params.timezone, token, now, now);
    const projectId = Number(result.lastInsertRowid);
    insertMembership.run(projectId, ctx.user.id, now, now);
    return { projectId, token };
  });

  const { projectId, token: projectToken } = transaction();

  return {
    success: true,
    project: {
      id: projectId,
      name: params.name,
      platform: params.platform,
      timezone: params.timezone,
      token: projectToken,
    },
  };
}

import { z } from "zod";
import { queryOne, execute } from "../db";
import type { UserContext } from "../auth";

export const deleteProjectSchema = z.object({
  project_id: z.number().describe("The project ID to delete"),
});

interface Project {
  id: number;
  name: string;
  deleted_at: string | null;
}

export function deleteProject(
  ctx: UserContext,
  params: z.infer<typeof deleteProjectSchema>
): object {
  if (ctx.user.role !== 0) {
    return { error: "Admin access required to delete projects" };
  }

  const project = queryOne<Project>(
    `SELECT id, name, deleted_at FROM projects WHERE id = ?`,
    [params.project_id]
  );

  if (!project || project.deleted_at) {
    return { error: "Project not found" };
  }

  if (!ctx.projectIds.includes(params.project_id)) {
    return { error: "Access denied to this project" };
  }

  const now = new Date().toISOString();
  execute(
    `UPDATE projects SET deleted_at = ?, updated_at = ? WHERE id = ?`,
    [now, now, params.project_id]
  );

  return {
    success: true,
    project_id: params.project_id,
    name: project.name,
    status: "deleted",
  };
}

import { z } from "zod";
import { queryOne, execute } from "../db";
import type { UserContext } from "../auth";

export const updateProjectSchema = z.object({
  project_id: z.number().describe("The project ID to update"),
  name: z.string().min(1).max(255).optional().describe("New project name"),
  timezone: z.string().optional().describe("New timezone (e.g. 'UTC', 'America/New_York')"),
});

interface Project {
  id: number;
  deleted_at: string | null;
}

export function updateProject(
  ctx: UserContext,
  params: z.infer<typeof updateProjectSchema>
): object {
  if (ctx.user.role !== 0) {
    return { error: "Admin access required to update projects" };
  }

  const project = queryOne<Project>(
    `SELECT id, deleted_at FROM projects WHERE id = ?`,
    [params.project_id]
  );

  if (!project || project.deleted_at) {
    return { error: "Project not found" };
  }

  if (!ctx.projectIds.includes(params.project_id)) {
    return { error: "Access denied to this project" };
  }

  if (!params.name && !params.timezone) {
    return { error: "Nothing to update — provide name or timezone" };
  }

  const now = new Date().toISOString();
  const sets: string[] = ["updated_at = ?"];
  const values: (string | number)[] = [now];

  if (params.name) {
    sets.push("name = ?");
    values.push(params.name);
  }
  if (params.timezone) {
    sets.push("timezone = ?");
    values.push(params.timezone);
  }

  values.push(params.project_id);
  execute(`UPDATE projects SET ${sets.join(", ")} WHERE id = ?`, values);

  return {
    success: true,
    project_id: params.project_id,
    updated: {
      ...(params.name ? { name: params.name } : {}),
      ...(params.timezone ? { timezone: params.timezone } : {}),
    },
  };
}

